import { unstable_cache } from 'next/cache';

export type Post = {
  id: string;
  title: string;
  body: string;
  createdAt: string;
};

// This is deliberately kept behind a data-access function so it can be replaced
// with a database query without changing the page or the Server Action.
const posts: Post[] = [
  {
    id: '1',
    title: 'Welcome',
    body: 'This is the first post.',
    createdAt: new Date(0).toISOString()
  }
];

async function readPosts(): Promise<Post[]> {
  return posts.map((post) => ({ ...post }));
}

/** The posts query is cached and associated with the `posts` cache tag. */
export const getPosts = unstable_cache(readPosts, ['posts-list'], {
  tags: ['posts']
});

export async function insertPost(title: string, body: string): Promise<Post> {
  const post: Post = {
    id: crypto.randomUUID(),
    title,
    body,
    createdAt: new Date().toISOString()
  };

  posts.unshift(post);
  return post;
}

'use server';

import { updateTag } from 'next/cache';
import { insertPost } from '../lib/posts';

export type CreatePostState = {
  error?: string;
  success?: string;
};

/**
 * Creates a post and immediately expires the posts tag.
 *
 * `updateTag` is intentional here (rather than `revalidateTag`): in a Server
 * Action it provides read-your-own-writes semantics. The next render waits for
 * a fresh value instead of serving stale cached posts.
 */
export async function createPost(
  _previousState: CreatePostState,
  formData: FormData
): Promise<CreatePostState> {
  const title = String(formData.get('title') ?? '').trim();
  const body = String(formData.get('body') ?? '').trim();

  if (!title || !body) {
    return { error: 'Title and body are required.' };
  }

  await insertPost(title, body);
  updateTag('posts');

  return { success: 'Post created.' };
}

'use client';

import { useActionState } from 'react';
import { createPost, type CreatePostState } from './actions';

const initialState: CreatePostState = {};

export function CreatePostForm() {
  const [state, formAction, pending] = useActionState(createPost, initialState);

  return (
    <form action={formAction}>
      <h2>Create a post</h2>
      <label>
        Title
        <input name="title" required maxLength={120} />
      </label>
      <label>
        Body
        <textarea name="body" required rows={4} />
      </label>
      <button type="submit" disabled={pending}>
        {pending ? 'Creating…' : 'Create post'}
      </button>
      {state.error && <p role="alert">{state.error}</p>}
      {state.success && <p role="status">{state.success}</p>}
    </form>
  );
}

import { CreatePostForm } from './create-post-form';
import { getPosts } from '../lib/posts';

export default async function Home() {
  const posts = await getPosts();

  return (
    <main>
      <h1>Posts</h1>
      <CreatePostForm />
      <section aria-labelledby="posts-heading">
        <h2 id="posts-heading">Latest posts</h2>
        {posts.length === 0 ? (
          <p>No posts yet.</p>
        ) : (
          <ul>
            {posts.map((post) => (
              <li key={post.id}>
                <article>
                  <h3>{post.title}</h3>
                  <p>{post.body}</p>
                </article>
              </li>
            ))}
          </ul>
        )}
      </section>
    </main>
  );
}
